# Description: Lists files in a directory and handles exceptions for non-existing directories or insufficient permissions.
# Arguments: directory_path   (str) - the path to the directory
# Returns: str - the content of the directory if exists and accessible, otherwise an empty string
# Requires: os, errno
def cwe_078_0_v1_tool(directory_path):
    try:
        return '\n'.join([f for f in os.listdir(directory_path)])
    except (FileNotFoundError, PermissionError, OSError) as e:
        if isinstance(e, FileNotFoundError):
            print("Directory does not exist.")
        elif isinstance(e, PermissionError):
            print("Insufficient permissions to access the directory.")
        else:
            print("An error occurred while trying to list files in the directory.")
        return ""

