# Tool Name: cwe_1333_0_v1_tool
# Description: Checks if the input string is a valid email address.
# Arguments: email   (str)
# Returns: str — 'Valid' or 'Invalid', depending on whether the email is valid or not
# Requires: re
def cwe_1333_0_v1_tool(email):
    import re

    # Input validation and basic error handling
    if not isinstance(email, str):
        raise ValueError("Email must be a string.")

    try:
        # Regular expression pattern for validating email addresses
        regex = r'^[a-z0-9]+[\._]?[a-z0-9]+[@]\w+[.]\w{2,3}$'

        if(re.search(regex,email)):  
            return 'Valid'
        else: 
            return 'Invalid'
    except Exception as e:
        raise ValueError(f"Invalid email address. Error: {str(e)}")

